  ('aboriginal-f0899a01-moex-00535', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-110-e2754278', 'sub-aboriginal-f0899a01-05', NULL, 'single_choice', '甲法警知悉某偵查中案件之進度，無故洩漏給媒體知悉。甲成立何罪？', '["刑法第132條第1項洩漏國防以外秘密罪", "刑法第110條公務員洩漏國防秘密罪", "刑法第316條無故洩漏業務秘密罪", "刑法第317條無故洩漏工商秘密罪"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:34+00:00", "source_pdf_sha1": "e6e107130816", "answer_pdf_sha1": "1c2f06e63016", "source_family": "moex-gov-tw", "moex": {"exam_code": "110150", "c": "507", "s": "0811", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "刑法概要", "year": "110", "exam_name": "110年公務人員特種考試外交領事人員及外交行政人員考試、民航人員考試、原住民族考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
